Search and filtering in a REST API is done using query parameters in the URL.

// Example: GET /users?name=John&age=25

const express = require('express');
const app = express();

const users = [
  { id: 1, name: 'John', age: 25, city: 'Ahmedabad' },
  { id: 2, name: 'Alice', age: 30, city: 'Surat' },
  { id: 3, name: 'Bob', age: 25, city: 'Ahmedabad' },
  { id: 4, name: 'John', age: 35, city: 'Baroda' }
];

app.get('/users', (req, res) => {
  let result = users;
  const { name, age, city } = req.query;

  // Filter by name if provided
  if (name) {
    result = result.filter(u => u.name.toLowerCase() === name.toLowerCase());
  }
  // Filter by age if provided
  if (age) {
    result = result.filter(u => u.age === parseInt(age));
  }
  // Filter by city if provided
  if (city) {
    result = result.filter(u => u.city.toLowerCase() === city.toLowerCase());
  }

  if (result.length === 0) {
    return res.status(404).json({ message: 'No users found' });
  }
  res.json(result);
});

app.listen(3000, () => console.log('Server running on port 3000'));

// Usage:
// GET /users              → all users
// GET /users?name=John    → users named John
// GET /users?age=25       → users aged 25
// GET /users?city=Surat   → users in Surat
// GET /users?name=John&age=25 → combined filter

const express = require('express');
const cookieParser = require('cookie-parser');
const app = express();
app.use(cookieParser());
app.use(express.urlencoded({ extended: true }));

app.get('/', (req, res) => {
  res.send(`
    <h2>Feedback Form</h2>
    <form action='/submit' method='GET'>
      Name: <input type='text' name='name' required /><br><br>
      Email: <input type='email' name='email' required /><br><br>
      Message: <textarea name='message'></textarea><br><br>
      Rating:
      <input type='radio' name='rating' value='Bad' />Bad
      <input type='radio' name='rating' value='Average' />Average
      <input type='radio' name='rating' value='Good' />Good
      <input type='radio' name='rating' value='Very Good' />Very Good
      <input type='radio' name='rating' value='Excellent' />Excellent<br><br>
      <input type='submit' value='Submit' />
    </form>
  `);
});

app.get('/submit', (req, res) => {
  const { name, email, message, rating } = req.query;
  const feedback = JSON.stringify({ name, email, message, rating });
  res.cookie('feedback', feedback, { maxAge: 10000 });
  res.send(`
    <h2>Thank you for your feedback, ${name}!</h2>
    <a href='/details'>View Feedback Details</a>
  `);
});

app.get('/details', (req, res) => {
  const feedback = req.cookies.feedback ? JSON.parse(req.cookies.feedback) : null;
  if (!feedback) {
    return res.send('<h2>Cookie expired or no feedback found.</h2><a href="/">Home</a>');
  }
  res.send(`
    <h2>Feedback Details</h2>
    <p>Name: ${feedback.name}</p>
    <p>Email: ${feedback.email}</p>
    <p>Message: ${feedback.message}</p>
    <p>Rating: ${feedback.rating}</p>
    <a href='/logout'>Logout</a>
  `);
});

app.get('/logout', (req, res) => {
  res.clearCookie('feedback');
  res.redirect('/');
});

app.listen(3000, () => console.log('Server on port 3000'));

