const express = require('express');
const cookieParser = require('cookie-parser');
const app = express();
app.use(cookieParser());
app.use(express.urlencoded({ extended: true }));

app.get('/', (req, res) => {
  res.send(`
    <form action='/calc' method='POST'>
      Number 1: <input type='number' name='num1' /><br><br>
      Number 2: <input type='number' name='num2' /><br><br>
      Formula:
      <select name='formula'>
        <option value=''>-- Select --</option>
        <option value='addition'>Addition</option>
        <option value='subtraction'>Subtraction</option>
        <option value='multiplication'>Multiplication</option>
        <option value='division'>Division</option>
      </select><br><br>
      <input type='submit' value='Calculate' />
    </form>
  `);
});

app.post('/calc', (req, res) => {
  const { num1, num2, formula } = req.body;
  const n1 = parseFloat(num1);
  const n2 = parseFloat(num2);

  if (!n1 || n1 <= 0 || !n2 || n2 <= 0) {
    return res.send('<h2 style="color:red;">Please enter valid number greater than 0</h2>');
  }
  if (!formula) {
    return res.send('<h2 style="color:red;">You have not selected any formula</h2>');
  }

  res.cookie('num1', num1, { maxAge: 50000 });
  res.cookie('num2', num2, { maxAge: 50000 });

  let result;
  if (formula === 'addition') result = n1 + n2;
  else if (formula === 'subtraction') result = n1 - n2;
  else if (formula === 'multiplication') result = n1 * n2;
  else if (formula === 'division') result = n2 !== 0 ? n1 / n2 : 'Cannot divide by zero';

  res.send(`<h2>${formula}: ${n1} and ${n2} = ${result}</h2>`);
});

app.listen(3000, () => console.log('Server on port 3000'));

Cookies are small pieces of data stored in the browser. In Express.js:

const express = require('express');
const cookieParser = require('cookie-parser');
const app = express();
app.use(cookieParser());

// Create/Set a cookie
app.get('/set', (req, res) => {
  res.cookie('username', 'LJU_Student', { maxAge: 60000 }); // expires in 60 seconds
  res.cookie('role', 'admin', { httpOnly: true }); // not accessible via JS
  res.send('Cookies have been set!');
});

// Read a cookie
app.get('/read', (req, res) => {
  const username = req.cookies.username;
  const role = req.cookies.role;
  res.send(`Username: ${username}, Role: ${role}`);
});

// Delete a cookie
app.get('/delete', (req, res) => {
  res.clearCookie('username');
  res.clearCookie('role');
  res.send('Cookies have been deleted!');
});

app.listen(3000, () => console.log('Server on port 3000'));

// Key points:
// - res.cookie(name, value, options) - sets cookie
// - req.cookies.name - reads cookie
// - res.clearCookie(name) - deletes cookie
// - maxAge: milliseconds until expiry
// - httpOnly: true prevents JavaScript access

