const express = require('express');
const app = express();
app.use(express.urlencoded({ extended: true }));

app.get('/', (req, res) => {
  res.send(`
    <form action='/discount' method='POST'>
      Product Price: <input type='number' name='price' /><br><br>
      Discount %: <input type='number' name='discount' /><br><br>
      Offer Type:
      <select name='offer'>
        <option value=''>-- Select Offer --</option>
        <option value='Festival Offer'>Festival Offer</option>
        <option value='Seasonal Offer'>Seasonal Offer</option>
        <option value='Clearance Sale'>Clearance Sale</option>
      </select><br><br>
      <input type='submit' value='Calculate Discount' />
    </form>
  `);
});

app.post('/discount', (req, res) => {
  const { price, discount, offer } = req.body;
  const p = parseFloat(price);
  const d = parseFloat(discount);

  if (!p || p <= 0 || !d || d <= 0) {
    return res.send('<h2 style="color:red;">Enter valid price and discount</h2>');
  }
  if (!offer) {
    return res.send('<h2 style="color:red;">Please select an offer type</h2>');
  }

  const discountedPrice = p - (p * d / 100);
  res.send(`
    <h2>Offer: ${offer}</h2>
    <p>Original Price: ₹${p}</p>
    <p>Discount: ${d}%</p>
    <p>Final Price: ₹${discountedPrice.toFixed(2)}</p>
  `);
});

app.listen(3000, () => console.log('Server on port 3000'));

